from flask import Flask, redirect, request, session
import requests

app = Flask(__name__)
app.secret_key = 'your_secret_key'

AUTHORIZATION_URL = 'https://authorization-server.com/oauth/authorize'
TOKEN_URL = 'https://authorization-server.com/oauth/token'
CLIENT_ID = 'your_client_id'
CLIENT_SECRET = 'your_client_secret'

@app.route('/login')
def login():
    state = 'random_state_string'  # Generate a random state string
    session['state'] = state
    params = {
        'response_type': 'code',
        'client_id': CLIENT_ID,
        'redirect_uri': 'http://localhost:5000/callback',
        'scope': 'openid email profile',
        'state': state
    }
    return redirect(AUTHORIZATION_URL + '?' + '&'.join([f'{k}={v}' for k, v in params.items()]))

@app.route('/callback')
def callback():
    if request.args.get('state') != session['state']:
        return 'Invalid state parameter', 400

    code = request.args.get('code')
    data = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': 'http://localhost:5000/callback',
        'client_id': CLIENT_ID,
        'client_secret': CLIENT_SECRET
    }
    response = requests.post(TOKEN_URL, data=data)
    access_token = response.json().get('access_token')
    if access_token:
        session['access_token'] = access_token
        return redirect('/')
    else:
        return 'Failed to get access token', 400

if __name__ == '__main__':
    app.run(debug=True)